s16 liboot_player_anim_id(const void *animation)
{
    for (u32 i = 0; i < sizeof(sLibootPlayerAnimations) /
                         sizeof(sLibootPlayerAnimations[0]); ++i) {
        if (animation == sLibootPlayerAnimations[i]) return (s16)(i + 1);
    }
    return 0;
}
